// Normaliza input y valida formato/honeypot antes de consultar BD.
const src = $input.first().json;
const body = src.body || src;
const email = (body.email || '').toString().trim().toLowerCase();
const phone = (body.phone || '').toString().trim();
const name = (body.name || '').toString().trim();
const company = (body.company || '').toString().trim();
const website = (body.website || '').toString().trim();
const ip = (src.headers && (src.headers['x-forwarded-for'] || src.headers['x-real-ip'])) || '';

if (website) {
  // Honeypot relleno — bot. Respondemos genérico.
  return [{ json: { ok: false, reason: 'validation_failed' } }];
}
if (!email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
  return [{ json: { ok: false, reason: 'invalid_email' } }];
}
if (!phone || phone.replace(/\D/g, '').length < 7) {
  return [{ json: { ok: false, reason: 'invalid_phone' } }];
}
if (!name) {
  return [{ json: { ok: false, reason: 'missing_name' } }];
}
return [{ json: { ok: true, email, phone, name, company, ip } }];

// Evalúa dedupe/rate-limit y arma respuesta final.
const norm = $('Normalize & format check').first().json;
const db = $input.first().json || {};
const userId = Number(db.user_id || 0);
const quoteCount = Number(db.quote_count || 0);
const blocked = db.blocked === true;
const recent = Number(db.recent_7d || 0);

if (blocked) {
  return [{ json: { ok: false, reason: 'blocked', message: db.block_reason || 'Contacto bloqueado. Escríbenos a info@alebas.co.' } }];
}
if (recent >= 5) {
  return [{ json: { ok: false, reason: 'rate_limit', message: 'Has solicitado muchas cotizaciones recientemente. Un ingeniero te contactará pronto.' } }];
}
return [{ json: {
  ok: true,
  userId,
  isReturning: userId > 0,
  priorQuotes: quoteCount,
  contact: { email: norm.email, phone: norm.phone, name: norm.name, company: norm.company },
} }];
